    auto field = std::make_shared<TrackingFieldNode>("field");

    auto &graph = ObserverGraph::getInstance();
    graph.addNode(owner);
    graph.addNode(field);

    auto &fieldGraph = FieldGraph::getInstance();
    fieldGraph.addObj(objectId, field);
    fieldGraph.bindField(objectId, owner);

