#include <memory>

namespace test_reaction {

struct LogicalExpressionSnapshot {
    bool initialAnd;
    bool initialOr;
    bool updatedAnd;
    bool updatedOr;
};

inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    // Create reactive variables
    auto varA = std::make_shared<reaction::VarExpr<bool>>(a);
    auto varB = std::make_shared<reaction::VarExpr<bool>>(b);
    auto varC = std::make_shared<reaction::VarExpr<bool>>(c);

    // Build logical expressions
    auto andExpr = *varA && *varB;
    auto orExpr = *varA || *varB;

    // Create reactive calculations
    auto calcAnd = reaction::createCalcExpr(andExpr);
    auto calcOr = reaction::createCalcExpr(orExpr);

    // Get initial results
    bool initialAnd = calcAnd->getValue();
    bool initialOr = calcOr->getValue();

    // Update variables to trigger recomputation
    varA->setValue(!a);
    varB->setValue(!b);

    // Get updated results
    bool updatedAnd = calcAnd->getValue();
    bool updatedOr = calcOr->getValue();

    return LogicalExpressionSnapshot{
        .initialAnd = initialAnd,
        .initialOr = initialOr,
        .updatedAnd = updatedAnd,
        .updatedOr = updatedOr
    };
}

}  // namespace test_reaction

