#pragma once

#include <reaction/expression/atomic_operations.h>
#include <cstdint>
#include <memory>

namespace test_reaction {

/**
 * Implementation of a reactive integer atomic variable helper.
 *
 * Manages its own integer value via a shared_ptr and tracks whether
 * the last operation caused a value change.
 */
class IntAtomicImpl {
public:
    explicit IntAtomicImpl(int32_t initial) 
        : m_weakPtr(std::make_shared<int32_t>(initial)), m_lastReportedChange(false) {}

    template <typename F, typename T>
    void atomicOperation(T &&op) {
        bool changed = reaction::atomicCompoundAssign(*m_weakPtr, std::forward<T>(op));
        m_lastReportedChange = changed;
    }

    template <typename F, typename T>
    void atomicOperation(T &&op, bool forceNotify) {
        bool changed = reaction::atomicCompoundAssign(*m_weakPtr, std::forward<T>(op));
        m_lastReportedChange = changed || forceNotify;
    }

    int32_t value() const { return *m_weakPtr; }
    bool lastReportedChange() const noexcept { return m_lastReportedChange; }

private:
    std::weak_ptr<int32_t> m_weakPtr;
    bool m_lastReportedChange;
};

/**
 * @brief Test the atomic compound assignment helper functions.
 *
 * Initializes an IntAtomicImpl, applies a series of compound assignments,
 * and records whether each operation caused a value change.
 *
 * @param initial The initial value to start with.
 * @return A snapshot of the final state and change flags.
 */
inline AtomicHelperSnapshot test_atomic_compound_helpers(int32_t initial) {
    IntAtomicImpl atomic(initial);
    bool addChanged = reaction::atomicAddAssign(atomic, 5);
    bool multiplyChanged = reaction::atomicMultiplyAssign(atomic, 2);
    bool andChanged = reaction::atomicBitwiseAndAssign(atomic, 3);
    bool leftShiftChanged = reaction::atomicLeftShiftAssign(atomic, 1);
    bool incrementChanged = reaction::atomicIncrement(atomic);
    return AtomicHelperSnapshot{
        .finalValue = atomic.value(),
        .addReportedChange = addChanged,
        .multiplyReportedChange = multiplyChanged,
        .andReportedChange = andChanged,
        .leftShiftReportedChange = leftShiftChanged,
        .incrementReportedChange = incrementChanged
    };
}

}  // namespace test_reaction
